// Deepfake-Erkennung fuer ein Bild via Sightengine (echte Wahrscheinlichkeit, kein LLM-Raten).
async function run(input) {
  const url = String((input && input.imageUrl) || '').trim();
  const apiUser = String((input && input.apiUser) || '').trim();
  const apiSecret = String((input && input.apiSecret) || '').trim();
  if (!/^https?:\/\//.test(url)) return { fehler: 'Bitte eine vollstaendige Bild-URL (http/https) angeben.' };
  if (!apiUser || !apiSecret) return { fehler: 'Sightengine api_user und api_secret noetig (Gratis-Tier auf sightengine.com).' };
  const ep = 'https://api.sightengine.com/1.0/check.json?models=deepfake'
    + '&api_user=' + encodeURIComponent(apiUser)
    + '&api_secret=' + encodeURIComponent(apiSecret)
    + '&url=' + encodeURIComponent(url);
  const res = await fetch(ep);
  const d = await res.json();
  if (d.status !== 'success') return { fehler: (d.error && d.error.message) || 'Pruefung fehlgeschlagen.' };
  const score = d.type && d.type.deepfake;
  if (score == null) return { fehler: 'Keine Deepfake-Bewertung erhalten.' };
  return {
    deepfakeWahrscheinlichkeit: Math.round(score * 1000) / 1000,
    prozent: Math.round(score * 100) + '%',
    einschaetzung: score >= 0.5 ? 'wahrscheinlich Deepfake/manipuliert' : 'wahrscheinlich echt',
    hinweis: 'Wahrscheinlichkeit, kein forensischer Beweis.',
    bild: url
  };
}
